import React from 'react'
import {Col} from "react-bootstrap"

const CardMovie = () => {
    return (
        <Col xs="6" sm="6" lg="3" md="4" className='my-1'>
            <div className='card'>
                <img className='card__image' src='pic1.jpeg' alt=''/>
                
            </div>
        </Col>
    )
}

export default CardMovie
